// Preparar query GraphQL para Printables
const input = $input.first().json;
const query = input.query || '';
const limit = input.limit || 5;

return {
  graphqlQuery: {
    operationName: 'SearchPrints',
    variables: {
      query: query,
      limit: limit,
      categoryId: null,
      ordering: '-download_count'
    },
    query: `query SearchPrints($query: String, $limit: Int, $categoryId: ID, $ordering: String) {
  prints(
    query: $query
    limit: $limit
    categoryId: $categoryId
    ordering: $ordering
  ) {
    items {
      id
      name
      slug
      summary
      firstImage {
        filePath
        rotation
      }
      user {
        publicUsername
        avatarFilePath
      }
      downloadCount
      likeCount
      makeCount
      category {
        name
      }
      tags {
        name
      }
    }
  }
}`
  },
  originalQuery: query
};

// Normalizar respuesta de Printables al formato RenderHub
const response = $input.first().json;
const items = response?.data?.prints?.items || [];
const query = $('Build GraphQL Query').first().json.originalQuery || '';

const BASE_IMG = 'https://media.printables.com/';
const BASE_URL = 'https://www.printables.com/model/';

const normalized = items.map(item => {
  const thumbPath = item.firstImage?.filePath || '';
  const thumbnail = thumbPath.startsWith('http') ? thumbPath : BASE_IMG + thumbPath;
  const tags = (item.tags || []).map(t => t.name).slice(0, 8);

  return {
    platform: 'Printables',
    id: String(item.id),
    name: item.name || '',
    description: item.summary || '',
    thumbnail_url: thumbnail,
    page_url: `${BASE_URL}${item.id}-${item.slug || item.id}`,
    download_url: `${BASE_URL}${item.id}-${item.slug || item.id}/files`,
    stl_direct: false,
    creator: item.user?.publicUsername || '',
    likes: item.likeCount || 0,
    downloads: item.downloadCount || 0,
    makes: item.makeCount || 0,
    category: item.category?.name || '',
    tags
  };
});

return {
  platform: 'Printables',
  query,
  count: normalized.length,
  results: normalized
};

